public class BinaryXOR {
    /**
     * Input are two strings a and b consisting only of 1s and 0s.
     * Perform binary XOR on these inputs and return result also as a string.
     * 
     * @param a binary string
     * @param b binary string
     * @return result of binary XOR as a string
     */
    public static String stringXor(String a, String b) {
        // Pad the shorter string with leading zeros
        int maxLength = Math.max(a.length(), b.length());
        a = String.format("%" + maxLength + "s", a).replace(' ', '0');
        b = String.format("%" + maxLength + "s", b).replace(' ', '0');

        StringBuilder result = new StringBuilder();
        for (int i = 0; i < maxLength; i++) {
            // Perform XOR operation
            if (a.charAt(i) == b.charAt(i)) {
                result.append('0');
            } else {
                result.append('1');
            }
        }
        return result.toString();
    }

    public static void main(String[] args) {
        System.out.println(stringXor("010", "110")); // Expected: '100'
        System.out.println(stringXor("01", "110"));   // Expected: '111'
        System.out.println(stringXor("1", "0"));       // Expected: '1'
        System.out.println(stringXor("0", "0"));       // Expected: '0'
        System.out.println(stringXor("111", "000"));   // Expected: '111'
        System.out.println(stringXor("1010", "110"));  // Expected: '1000'
    }
}
