public class HexadecimalXOR {
    /**
     * Input are two strings a and b consisting only of hexadecimal digits.
     * Perform binary XOR on these inputs and return result also as a string.
     * 
     * @param a hexadecimal string
     * @param b hexadecimal string
     * @return result of binary XOR as a string
     */
    public static String hexXor(String a, String b) {
        // Pad the shorter string with leading zeros
        int maxLength = Math.max(a.length(), b.length());
        a = String.format("%" + maxLength + "s", a).replace(' ', '0');
        b = String.format("%" + maxLength + "s", b).replace(' ', '0');

        StringBuilder result = new StringBuilder();
        for (int i = 0; i < maxLength; i++) {
            // Convert hex characters to integers, perform XOR, and convert back to hex
            int xorValue = Integer.parseInt(String.valueOf(a.charAt(i)), 16) ^ Integer.parseInt(String.valueOf(b.charAt(i)), 16);
            result.append(Integer.toHexString(xorValue).toUpperCase());
        }
        return result.toString();
    }

    public static void main(String[] args) {
        System.out.println(hexXor("1A3", "4F2")); // Example usage
        System.out.println(hexXor("FF", "0F"));   // Example usage
        System.out.println(hexXor("A", "B"));     // Example usage
    }
}
